<?php
/**
 * AJAX: Return Library Book
 * 
 * @author School ERP Development Team
 * @version 1.0.0
 */

// Start output buffering FIRST to catch any unwanted output
ob_start();

require_once '../../config/config.php';

// NOW suppress error display AFTER config is loaded
error_reporting(E_ALL);
ini_set('display_errors', 0);
ini_set('display_startup_errors', 0);

// Clear any output that might have been generated by config.php
ob_clean();

// Set JSON header early
header('Content-Type: application/json; charset=utf-8');
header('Cache-Control: no-cache, must-revalidate');

// Support both session-based (web) and user_id parameter (Flutter/mobile) authentication
$currentUser = null;
$userId = $_POST['user_id'] ?? json_decode(file_get_contents('php://input'), true)['user_id'] ?? null;

if ($userId) {
    // Flutter/mobile app authentication
    $sql = "SELECT u.*, r.role_name, b.branch_name 
            FROM users u 
            LEFT JOIN roles r ON u.role_id = r.id 
            LEFT JOIN branches b ON u.branch_id = b.id 
            WHERE u.id = ? AND u.is_active = 1";
    $stmt = executeQuery($sql, 'i', [$userId]);
    $currentUser = fetchOne($stmt);
    
    if (!$currentUser) {
        jsonResponse(false, 'Invalid user ID');
    }
    
    $allowedRoles = ['Super Admin', 'Admin', 'Librarian'];
    if (!in_array($currentUser['role_name'], $allowedRoles)) {
        jsonResponse(false, 'Permission denied');
    }
} else {
    // Web session-based authentication
    if (!isLoggedIn()) jsonResponse(false, 'Unauthorized');
    if (!hasRole(['Super Admin', 'Admin', 'Librarian'])) jsonResponse(false, 'Permission denied');
    $currentUser = getCurrentUser();
}

$input = file_get_contents('php://input');
$data = json_decode($input, true);

if (!$data) {
    $data = $_POST;
}

$issueId = $data['issue_id'] ?? 0;
$returnDate = $data['return_date'] ?? date('Y-m-d');
$fineAmount = $data['fine_amount'] ?? 0;
$remarks = sanitize($data['remarks'] ?? '');

if (empty($issueId)) {
    jsonResponse(false, 'Issue ID is required');
}

beginTransaction();

try {
    // Get issue details
    $issueSql = "SELECT * FROM library_issues WHERE id = ?";
    $issueStmt = executeQuery($issueSql, 'i', [$issueId]);
    $issue = fetchOne($issueStmt);
    
    if (!$issue) {
        jsonResponse(false, 'Issue record not found');
    }
    
    if ($issue['status'] == 'Returned') {
        jsonResponse(false, 'Book already returned');
    }
    
    // Calculate fine if overdue
    $calculatedFine = 0;
    if ($issue['due_date']) {
        $dueDate = new DateTime($issue['due_date']);
        $returnDateTime = new DateTime($returnDate);
        if ($returnDateTime > $dueDate) {
            $daysOverdue = $returnDateTime->diff($dueDate)->days;
            $calculatedFine = $daysOverdue * 5.0; // $5 per day
        }
    }
    
    // Use provided fine amount or calculated fine
    $finalFine = $fineAmount > 0 ? $fineAmount : $calculatedFine;
    
    // Update issue record
    $updateSql = "UPDATE library_issues 
                  SET return_date = ?, status = 'Returned', fine_amount = ?, remarks = ?, returned_to = ?
                  WHERE id = ?";
    
    $updateStmt = executeQuery($updateSql, 'sdssi', [
        $returnDate, $finalFine, $remarks, $currentUser['id'], $issueId
    ]);
    
    if (!$updateStmt) {
        throw new Exception('Failed to update issue record');
    }
    
    // Update book availability
    $bookSql = "UPDATE library_books SET available_quantity = available_quantity + 1 WHERE id = ?";
    executeQuery($bookSql, 'i', [$issue['book_id']]);
    
    logActivity($currentUser['id'], 'Return Book', 'Library', "Returned book issue ID: $issueId");
    
    commitTransaction();
    jsonResponse(true, 'Book returned successfully!' . ($finalFine > 0 ? " Fine: $" . number_format($finalFine, 2) : ''));
    
} catch (Exception $e) {
    rollbackTransaction();
    jsonResponse(false, 'Failed to return book: ' . $e->getMessage());
}
